  { "kind": "reps-exercise",       "name": "<pool reps name>",       "sets": 3, "reps": 12, "restSec": 60, "weightNote": "3-5 kg" }
  { "kind": "timed-exercise",      "name": "<pool timed name>",      "sets": 3, "durationSec": 30, "restSec": 30, "weightNote": "" }
